function calcSize() {
	let finalWidth = 0,
		finalHeight = 0,
		finalTop = 0,
		finalLeft = 0;

	// const width = document.body.offsetWidth;
	// const height = document.body.offsetHeight;
	const width = window.innerWidth;
	const height = window.innerHeight;
	const curRatio = height / width;
	const minRatio = 1440 / 810;
	const maxRatio = 1800 / 810;
	if (curRatio < minRatio) {
		finalHeight = height;
		finalWidth = height / minRatio;
	} else if (curRatio > maxRatio) {
		finalWidth = width;
		finalHeight = width * maxRatio;
	} else {
		finalHeight = height;
		finalWidth = width;
	}

    window.configurationHeight = `${(finalHeight/finalWidth)*360}`
    window.paytableContentHeight = `${(finalHeight/finalWidth)*360-63}`

	return {
		width: finalWidth,
		height: finalHeight,
		top: (height - finalHeight) / 2,
		left: (width - finalWidth) / 2
	};
}

window.resetGameView = function resetGameView() {
	const div = document.getElementById("game-box");
	if (!div) {
		return;
	}

	const size = calcSize();
	div.style.height = `${size.height}px`;
	div.style.width = `${size.width}px`;
	div.style.top = `${size.top}px`;
	div.style.left = `${size.left}px`;

    // 后面阴影
    const shadowDiv = document.getElementById("canvas-shadow");
    if (shadowDiv) {
        shadowDiv.style.height = `${size.height}px`;
        shadowDiv.style.width = `${size.width}px`;
        shadowDiv.style.top = `${size.top}px`;
        shadowDiv.style.left = `${size.left}px`;
    }

    const overlay = document.getElementById("game-overlay");
    if (!overlay) {
        return;
    }
    overlay.style.left = `${size.left}px`;
    overlay.style.top = `${size.top}px`;
    overlay.style.transform = `scale(${size.width / 360}) rotate(0deg)`;
	
	let splash = document.getElementById('splash')
	splash.style.height = `${(size.height/size.width)*360}px`;
	
	let gameHistory = document.getElementById('game-history-container')
	if (gameHistory) {
		gameHistory.style.height = `${(size.height/size.width)*360}px`;
	}

    let paytableContainer = document.getElementById('paytable-container')
	if (paytableContainer) {
		paytableContainer.style.height = `${(size.height/size.width)*360}px`;
	}
    let paytableContent = document.getElementById('paytable-content')
	if (paytableContent) {
		paytableContent.style.height = `${(size.height/size.width)*360-63}px`;
	}

    let gameRulesContainer = document.getElementById('game-rules-container')
	if (gameRulesContainer) {
		gameRulesContainer.style.height = `${(size.height/size.width)*360}px`;
	}
    let rulesContent = document.getElementById('rulesContent')
	if (rulesContent) {
		rulesContent.style.height = `${(size.height/size.width)*360-63}px`;
	}

    let ui_block = document.getElementById('ui_block')
	if (ui_block) {
		ui_block.style.height = `${(size.height/size.width)*360}px`;
	}
    let ghVrfPopupAnimBG = document.getElementById('ghVrfPopupAnim-BG')
	if (ghVrfPopupAnimBG) {
		ghVrfPopupAnimBG.style.height = `${(size.height/size.width)*360}px`;
	}

	
	let loadingPanel = document.getElementById('loading_panel')
	if (loadingPanel) {
		loadingPanel.style.height = `${(size.height/size.width)*360}px`;
	}

    let screenSafeAreaHeight = ((size.height/size.width)*360-640) / 2
	let socialWidgetContainer = document.getElementById('social_widget-container')
	let trophiesBottom = window.sessionStorage.getItem("trophiesCoordinateBottom");
	trophiesBottom = parseInt(trophiesBottom)+parseInt(screenSafeAreaHeight)
	let trophiesLeft = window.sessionStorage.getItem("trophiesCoordinateLeft");
	if(socialWidgetContainer != null){
		socialWidgetContainer.style.transform = `translate(${trophiesLeft}px,${trophiesBottom}px)`
	}

	let genericBackgroundView = document.getElementById('footer-main-tournament-view')
	if(genericBackgroundView != null){
		
		genericBackgroundViewLeft = 0;
		genericBackgroundViewBottom = (size.height/size.width)*360-640;
		genericBackgroundView.style.transform = `translate(${genericBackgroundViewLeft}px,${genericBackgroundViewBottom}px)`
	}


}

resetGameView();

window.addEventListener("resize", resetGameView);