<script>
export default {
	computed: {
		splashStyle() {
			this.currentLang = this.$i18n.locale
			const imgMap = {
				en: require('@/assets/image/en/startup.jpg'),
				pt: require('@/assets/image/pt/startup.jpg'),
				ru: require('@/assets/image/ru/startup.jpg')
			}
			const bgUrl = imgMap[this.currentLang] || imgMap['en']

			return {
				position: 'absolute',
				top: 0,
				left: 0,
				width: '360px',
				height: `${this.configurationHeight}px`, // 使用动态窗口尺寸
				backgroundColor: '#171717',
				backgroundImage: `url('${bgUrl}')`,
				backgroundRepeat: 'no-repeat',
				backgroundPosition: 'center',
				backgroundSize: 'cover',
			}
		}
	},

	components: {

	},
	data() {
		return {
			gameId: null,
			currentLang: this.$i18n.locale,
			timeStamp: '00:00:00',
			showLoading: false,
			trophiesCoordinateBottom: 120,
			trophiesCoordinateLeft: 360,
			gameInfo: {
				jbicon_pos: "123,123",
				name: "mouse"
			},
			animationDuration: 0.75,
			brandName: 'kf',
			imgUrl: process.env.VUE_APP_IMG_URL || 'https://testcdnupload.pg-gub.com/common',
		}
	},
	created() {
			
		this.brandName = this.getParams("brandName") || 'kf'
	},
	mounted() {
		// 监听窗口大小变化
		window.addEventListener('resize', this.updateWindowSize);

		let nav1 = document.createElement('script')
		nav1.type = 'text/javascript'
		nav1.src = require('@/assets/js/view.js')

		let nav = document.createElement('script')
		nav.type = 'text/javascript'
		nav.src = require('@/assets/js/game_index.js')

		let nav2 = document.createElement('script')
		nav2.type = 'text/javascript'
		nav2.src = require('@/assets/js/info.js')

		setInterval(this.getCurrentTime, 1000)

		this.gameId = this.getParams("game_id")
		if (this.gameId) {
			this.getGame()
		}

		window.token = this.getParams("token")
		window.gameId = this.gameId

		localStorage.setItem("token", window.token)
		localStorage.setItem("gameId", window.gameId)

		this.reloadAnimation();
	},
	beforeDestroy() {
		// 移除事件监听器
		window.removeEventListener('resize', this.updateWindowSize);
	},
	methods: {
		reloadAnimation() {
			const img = this.$refs.animatedGif;
			const originalSrc = img.src;

			// 清空src再重新设置
			img.src = 'data:image/gif;base64,R0lGODlhAQABAIAAAP///wAAACH5BAEAAAAALAAAAAABAAEAAAICRAEAOw==';

			// 使用setTimeout确保重载生效
			setTimeout(() => {
				img.src = `${originalSrc}?t=${Date.now()}`;
			}, 50);
		},
		updateWindowSize() {
			this.configurationHeight = window.configurationHeight
		},

		guid() {
			return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
				var r = Math.random() * 16 | 0,
					v = c == 'x' ? r : (r & 0x3 | 0x8);
				return v.toString(16);
			});
		},
		// 加载时调用 加载后调用
		changeLoading() {
			this.showLoading = !this.showLoading
		},

		getCurrentTime() {
			//获取当前时间并打印
			var _this = this;
			let hh = new Date().getHours();
			let mf = new Date().getMinutes() < 10 ? '0' + new Date().getMinutes() : new Date().getMinutes();
			let ss = new Date().getSeconds() < 10 ? '0' + new Date().getSeconds() : new Date().getSeconds();
			_this.timeStamp = hh + ':' + mf + ':' + ss;
		},
		getGame() {
			this.$http.get('/api/game/get_config', {
				params: {
					game_id: this.gameId
				}
			}).then(response => {
				if (response.data.meta.code == 0) {
					this.gameInfo = response.data.data
					if (this.gameInfo.jbicon_pos.length) {
						let trophiesCoordinate = this.gameInfo.jbicon_pos.split(",")
						this.trophiesCoordinateBottom = trophiesCoordinate[1]
						this.trophiesCoordinateLeft = trophiesCoordinate[0]
					}
					window.sessionStorage.setItem("trophiesCoordinateLeft", this.trophiesCoordinateLeft);
					window.sessionStorage.setItem("trophiesCoordinateBottom", this.trophiesCoordinateBottom);
				}
			});
		},
		getParams(name) {
			var reg = new RegExp("(^|&)" + name + "=([^&]*)(&|$)");
			var r = decodeURI(window.location.search).substr(1).match(reg);
			if (r != null) {
				return unescape(r[2]);
			} else {
				return null;
			}
		},
	}
}
</script>